import { defineComponentStyle } from "@yamada-ui/react"

export const centerStyle = defineComponentStyle({
  base: {
    display: "flex",
    placeContent: "center",
    placeItems: "center",
  },
})

export type CenterStyle = typeof centerStyle

import { a11y, page, render } from "#test/browser"
import { Center } from "./center"

describe("<Center />", () => {
  test("renders component correctly", async () => {
    await a11y(<Center>Center</Center>)
  })

  test("sets `displayName` correctly", () => {
    expect(Center.displayName).toBe("Center")
  })

  test("sets `className` correctly", async () => {
    await render(<Center>Center</Center>)

    await expect.element(page.getByText("Center")).toHaveClass("ui-center")
  })

  test("renders HTML tag correctly", async () => {
    await render(<Center>Center</Center>)

    expect(page.getByText("Center").element().tagName).toBe("DIV")
  })
})

"use client"

import type { HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { CenterStyle } from "./center.style"
import { createComponent } from "@yamada-ui/react"
import { centerStyle } from "./center.style"

export interface CenterProps extends HTMLStyledProps, ThemeProps<CenterStyle> {}

const {
  PropsContext: CenterPropsContext,
  usePropsContext: useCenterPropsContext,
  withContext,
} = createComponent<CenterProps, CenterStyle>("center", centerStyle)

export { CenterPropsContext, useCenterPropsContext }

/**
 * `Center` is a component that aligns the child elements in the center within the component.
 *
 * @see https://yamada-ui.com/docs/components/center
 */
export const Center = withContext("div", {
  base: {
    display: "flex",
    placeContent: "center",
    placeItems: "center",
  },
})()
